            m3 = re.search(r'including (.+)', s, flags=re.IGNORECASE)
            if m3:
                piece = m3.group(1)
            else:
                m4 = re.search(r'offers a range of services in (.+)', s, flags=re.IGNORECASE)
                if m4:
                    piece = m4.group(1)
                else:
                    m5 = re.search(r'offers a wide range of services in (.+)', s, flags=re.IGNORECASE)
